mapper.select:
SELECT id, user_id, method_type, secret_hash, is_active
FROM user_auth_methods
WHERE user_id = #{userId}
  AND method_type = #{methodType}

mapper.insert:
INSERT INTO user_auth_methods (user_id, method_type, secret_hash)
VALUES (#{userId}, #{methodType}, #{secretHash})
ON DUPLICATE KEY UPDATE secret_hash = #{secretHash}
